<?phpnamespace App\Http\Controllers\Api;use App\Models\ServiceArea;use App\Models\City;use App\Models\Currency;use App\Models\DeliveryRider;use App\Models\FavoriteSeller;use App\Models\Order;use App\Models\PaymentGateway;use App\Models\RiderServiceArea;use Illuminate\Http\Request;use Illuminate\Support\Facades\Hash;use Validator;use App\Http\Resources\ServiceAreaResource;class GeneralController{    public function serviceAreas()    {        $service_area = ServiceArea::orderBy('id', 'desc')->get();        return response()->json(['status'=>true,'data'=>ServiceAreaResource::collection($service_area)]);    }    }